import java.io.BufferedInputStream;import java.util.TreeSet
private class FS{val input=BufferedInputStream(System.`in`);val b=ByteArray(1 shl 16);var l=0;var p=0;fun rb():Int{if(p>=l){l=input.read(b);p=0;if(l<=0)return -1};return b[p++].toInt()}fun next():String{var c=rb();while(c<=32&&c>=0)c=rb();val s=StringBuilder();while(c>32){s.append(c.toChar());c=rb()};return s.toString()}}
fun snap(s:TreeSet<Int>):String{val parts=mutableListOf<String>();var open=false;var st=0;var prev=0;for(v in s){if(!open){st=v;prev=v;open=true}else if(v==prev+1)prev=v else{parts.add("[$st,$prev]");st=v;prev=v}};if(open)parts.add("[$st,$prev]");return "["+parts.joinToString(",")+"]"}
fun main(){val fs=FS();val t=fs.next().toInt();val cases=mutableListOf<String>();repeat(t){val ops=fs.next().toInt();val seen=TreeSet<Int>();val snaps=mutableListOf<String>();repeat(ops){val op=fs.next();if(op=="A")seen.add(fs.next().toInt())else snaps.add(snap(seen))};cases.add("["+snaps.joinToString(",")+"]")};print(cases.joinToString("\n\n"))}
